// Script Continued Below
/*jshint esnext: true */
var tcs  = new TaskerCommonScriptingMethods();
var userTableName = "sys_user";
var ouMemberTableName = "x_153465_discovert_discover_office_members";

//synchronizes all checked fields with the found member records
var allUsers = tcs.queryRelated(userTableName, null, function(user) {
	var ouMemberQuery = [{"office_member": user.sys_id}];
	var modCount = 0;
	tcs.queryRelated(ouMemberTableName, ouMemberQuery, function(memberRecord) {
		memberRecord.sys_mod_count++;
		memberRecord.update();
		modCount++;
		return null;
	});
	if(modCount > 0) {
		tcs.commonMessage("OU Perm Fix", "User: " + user.name + " "+ modCount+ " record(s) updated.", gs.info );
	}
	modCount = 0;
});

// STRY0047772 - Validate all users in the Members Table have Tasker User Role
var UserPermissions = new UserInfoScripts();
var iCountMissingTaskerUsers = 0;
var iCountMembersProcessed = 0;
var iCountTaskerUsersCorrected = 0;
var grMembers = new GlideRecord('x_153465_discovert_discover_office_members');
grMembers.query();
while(grMembers.next()){
	var memName;
	try {
		memName = gr_PT_Rename.getValue("office_member");

		iCountMembersProcessed += 1;
		if(!UserPermissions.UserHasRoleScoped('x_153465_discovert.tasker_user', grMembers.office_member)){
			iCountMissingTaskerUsers += 1;
			if(UserPermissions.addRole(grMembers.office_member, 'x_153465_discovert.tasker_user')){
				gs.info('Synchronize member Script update - Role x_153465_discovert.tasker_user : ' + grMembers.office_member.first_name + ' ' + grMembers.office_member.middle_name + ' ' + grMembers.office_member.last_name);	
				iCountTaskerUsersCorrected +=1;
			}
		}
	} catch(e){
		gs.error("Member Name:" + memName + " - Error in 'Synchronize OU Member Permissions' - exception: " + e);
	}

}
gs.info('Synchronize member Script reviewed: ' + iCountMembersProcessed + ' users.  A total of: ' + iCountMissingTaskerUsers + ' users were missing the Task User role.  A total of ' + iCountTaskerUsersCorrected + ' were successfully updated');
